import React, { useEffect, useState } from "react";
import axios from "axios";
import { useAuth } from "../context/AuthContext";
import InternshipCard from "../components/InternshipCard";
import { useNavigate } from "react-router-dom";

export default function Internship() {
  const { currentUser } = useAuth();
  const [internships, setInternships] = useState([]);
  const [searchTerm, setSearchTerm] = useState("");
  const [filterLocation, setFilterLocation] = useState("");
  const [filterCompany, setFilterCompany] = useState("");
  const navigate = useNavigate();

  const fetchInternships = async () => {
    try {
      const res = await axios.get("http://localhost:5000/api/internships");
      setInternships(res.data);
    } catch (err) {
      console.error("Failed to fetch internships:", err);
    }
  };

  useEffect(() => {
    fetchInternships();
  }, []);

  const filteredInternships = internships.filter((internship) => {
    return (
      internship.title.toLowerCase().includes(searchTerm.toLowerCase()) &&
      internship.location.toLowerCase().includes(filterLocation.toLowerCase()) &&
      internship.company.toLowerCase().includes(filterCompany.toLowerCase())
    );
  });

  return (
    <div className="p-6">
      <h1 className="text-3xl font-bold mb-4">Available Internships</h1>

      {/* Admin/HR Only: Post Internship Button */}
      {(currentUser?.role === "admin" || currentUser?.role === "hr") && (
        <button
          onClick={() => navigate("/post-internship")}
          className="bg-green-600 text-white px-4 py-2 rounded mb-4"
        >
          Post Internship
        </button>
      )}

      {/* Search & Filters */}
      <div className="flex flex-wrap gap-4 mb-4">
        <input
          type="text"
          placeholder="Search by Title"
          value={searchTerm}
          onChange={(e) => setSearchTerm(e.target.value)}
          className="border px-3 py-2 rounded w-full sm:w-auto"
        />
        <input
          type="text"
          placeholder="Filter by Location"
          value={filterLocation}
          onChange={(e) => setFilterLocation(e.target.value)}
          className="border px-3 py-2 rounded w-full sm:w-auto"
        />
        <input
          type="text"
          placeholder="Filter by Company"
          value={filterCompany}
          onChange={(e) => setFilterCompany(e.target.value)}
          className="border px-3 py-2 rounded w-full sm:w-auto"
        />
      </div>

      {/* Internship Cards */}
      <div className="grid gap-4">
        {filteredInternships.length > 0 ? (
          filteredInternships.map((internship) => (
            <InternshipCard
              key={internship._id}
              internship={internship}
              fetchInternships={fetchInternships}
            />
          ))
        ) : (
          <p>No internships found.</p>
        )}
      </div>
    </div>
  );
}
